configuration.decoder:
// Phase 2 uplink converter
// Incoming MQTT topic: campus/b01/fXX/rYYY/{telemetry|heartbeat|status|response|summary}
// Telemetry MUST use [{ ts, values }] — flat objects with a "ts" key are not reliable in TB 3.7 integrations.
var topic = metadata['mqtt_topicName'] || metadata['topic'] || '';
var parts = topic.split('/');
if (parts.length < 5) {
    return { deviceName: 'unknown', deviceType: 'MQTT-ThermalSensor', telemetry: [{ ts: Date.now(), values: {} }] };
}
var building = parts[1];
var floor = parts[2];
var room = parts[3];
var suffix = parts[4];
var deviceName = building + '-' + floor + '-' + room;
var roomNum = parseInt(String(room).replace(/^r/, ''), 10) || 0;
var isCoap = roomNum % 100 >= 11;
var deviceType = isCoap ? 'CoAP-ThermalSensor' : 'MQTT-ThermalSensor';
var result = {
    deviceName: deviceName,
    deviceType: deviceType,
    attributes: {
        floor: floor,
        room: room,
        building: building,
        transport: isCoap ? 'coap' : 'mqtt'
    },
    telemetry: [{ ts: Date.now(), values: {} }]
};
var data = (typeof decodedPayload === 'string') ? JSON.parse(decodedPayload) : decodedPayload;
if (suffix === 'telemetry') {
    var tsMs = (data.timestamp != null && data.timestamp > 0) ? data.timestamp * 1000 : Date.now();
    result.telemetry = [{
        ts: tsMs,
        values: {
            temperature: data.temperature,
            humidity: data.humidity,
            occupancy: data.occupancy,
            light_level: data.light_level,
            hvac_mode: data.hvac_mode,
            lighting_dimmer: data.lighting_dimmer
        }
    }];
} else if (suffix === 'heartbeat') {
    var tsHb = (data.timestamp != null && data.timestamp > 0) ? data.timestamp * 1000 : Date.now();
    result.telemetry = [{ ts: tsHb, values: { heartbeat_ts: tsHb, status: data.status || 'Healthy' } }];
} else if (suffix === 'status') {
    result.attributes.state = data.state || 'unknown';
    result.telemetry = [{ ts: Date.now(), values: { state: data.state } }];
} else if (suffix === 'response') {
    result.telemetry = [{ ts: Date.now(), values: { response: data } }];
}
return result;

configuration.encoder:
// Phase 2 downlink converter: RPC request -> MQTT cmd
var deviceName = msg.deviceName || metadata['deviceName'];
var m = deviceName.match(/^(b\d{2})-(f\d{2})-(r\d+)$/);
if (!m) { return { topic: 'campus/dead-letter', payload: {} }; }
var topic = 'campus/' + m[1] + '/' + m[2] + '/' + m[3] + '/cmd';
return { topic: topic, qos: 2, payload: msg, metadata: { contentType: 'application/json' } };
